package com.jwebmp.website.catalog;

import lombok.Getter;

import java.util.Collections;
import java.util.List;
import java.util.Map;

@Getter
public final class PluginEntry
{
    // ── Identity ──────────────────────────────────────
    private final String id;
    private final String name;
    private final String category;
    private final String description;

    // ── Maven coordinates ─────────────────────────────
    private final String groupId;
    private final String artifactId;
    private final String version;

    // ── Upstream library ──────────────────────────────
    private final String upstreamName;
    private final String upstreamVersion;
    private final String upstreamUrl;

    // ── JPMS ──────────────────────────────────────────
    private final String jpmsModule;

    // ── README & docs ─────────────────────────────────
    private final String readmePath;
    private final String docsUrl;
    private final String sourceUrl;

    // ── Features ──────────────────────────────────────
    private final List<String> features;

    // ── Tech badges ───────────────────────────────────
    private final List<String> techBadges;

    // ── Prerequisites ─────────────────────────────────
    private final List<String> prerequisites;

    // ── NPM dependencies (name → version) ─────────────
    private final Map<String, String> npmDependencies;

    // ── Quick start snippet ───────────────────────────
    private final String quickStartCode;
    private final String quickStartLanguage;

    // ── Installation snippet ──────────────────────────
    private final String mavenSnippet;
    private final String gradleSnippet;

    // ── License info ──────────────────────────────────
    private final boolean requiresLicense;
    private final String licenseNote;

    // ── SPI extensions provided ───────────────────────
    private final List<String> spiProvides;

    // ── SPI extensions consumed ───────────────────────
    private final List<String> spiUses;

    private PluginEntry(Builder builder)
    {
        this.id = builder.id;
        this.name = builder.name;
        this.category = builder.category;
        this.description = builder.description;
        this.groupId = builder.groupId;
        this.artifactId = builder.artifactId;
        this.version = builder.version;
        this.upstreamName = builder.upstreamName;
        this.upstreamVersion = builder.upstreamVersion;
        this.upstreamUrl = builder.upstreamUrl;
        this.jpmsModule = builder.jpmsModule;
        this.readmePath = builder.readmePath;
        this.docsUrl = builder.docsUrl;
        this.sourceUrl = builder.sourceUrl;
        this.features = builder.features == null ? List.of() : Collections.unmodifiableList(builder.features);
        this.techBadges = builder.techBadges == null ? List.of() : Collections.unmodifiableList(builder.techBadges);
        this.prerequisites = builder.prerequisites == null ? List.of() : Collections.unmodifiableList(builder.prerequisites);
        this.npmDependencies = builder.npmDependencies == null ? Map.of() : Collections.unmodifiableMap(builder.npmDependencies);
        this.quickStartCode = builder.quickStartCode;
        this.quickStartLanguage = builder.quickStartLanguage;
        this.mavenSnippet = builder.mavenSnippet;
        this.gradleSnippet = builder.gradleSnippet;
        this.requiresLicense = builder.requiresLicense;
        this.licenseNote = builder.licenseNote;
        this.spiProvides = builder.spiProvides == null ? List.of() : Collections.unmodifiableList(builder.spiProvides);
        this.spiUses = builder.spiUses == null ? List.of() : Collections.unmodifiableList(builder.spiUses);
    }

    public static Builder builder(String id, String name, String category, String groupId, String artifactId)
    {
        return new Builder(id, name, category, groupId, artifactId);
    }

    public static final class Builder
    {
        private final String id;
        private final String name;
        private final String category;
        private final String groupId;
        private final String artifactId;

        private String description;
        private String version = "2.0.0-SNAPSHOT";
        private String upstreamName;
        private String upstreamVersion;
        private String upstreamUrl;
        private String jpmsModule;
        private String readmePath;
        private String docsUrl;
        private String sourceUrl;
        private List<String> features;
        private List<String> techBadges;
        private List<String> prerequisites;
        private Map<String, String> npmDependencies;
        private String quickStartCode;
        private String quickStartLanguage = "java";
        private String mavenSnippet;
        private String gradleSnippet;
        private boolean requiresLicense;
        private String licenseNote;
        private List<String> spiProvides;
        private List<String> spiUses;

        private Builder(String id, String name, String category, String groupId, String artifactId)
        {
            this.id = id;
            this.name = name;
            this.category = category;
            this.groupId = groupId;
            this.artifactId = artifactId;
        }

        public Builder description(String val) { description = val; return this; }
        public Builder version(String val) { version = val; return this; }
        public Builder upstreamName(String val) { upstreamName = val; return this; }
        public Builder upstreamVersion(String val) { upstreamVersion = val; return this; }
        public Builder upstreamUrl(String val) { upstreamUrl = val; return this; }
        public Builder jpmsModule(String val) { jpmsModule = val; return this; }
        public Builder readmePath(String val) { readmePath = val; return this; }
        public Builder docsUrl(String val) { docsUrl = val; return this; }
        public Builder sourceUrl(String val) { sourceUrl = val; return this; }
        public Builder features(List<String> val) { features = val; return this; }
        public Builder techBadges(List<String> val) { techBadges = val; return this; }
        public Builder prerequisites(List<String> val) { prerequisites = val; return this; }
        public Builder npmDependencies(Map<String, String> val) { npmDependencies = val; return this; }
        public Builder quickStartCode(String val) { quickStartCode = val; return this; }
        public Builder quickStartLanguage(String val) { quickStartLanguage = val; return this; }
        public Builder mavenSnippet(String val) { mavenSnippet = val; return this; }
        public Builder gradleSnippet(String val) { gradleSnippet = val; return this; }
        public Builder requiresLicense(boolean val) { requiresLicense = val; return this; }
        public Builder licenseNote(String val) { licenseNote = val; return this; }
        public Builder spiProvides(List<String> val) { spiProvides = val; return this; }
        public Builder spiUses(List<String> val) { spiUses = val; return this; }

        public PluginEntry build()
        {
            return new PluginEntry(this);
        }
    }
}

package com.jwebmp.website.catalog;

import lombok.Getter;

import java.util.Collections;
import java.util.List;
import java.util.Map;

@Getter
public final class PluginEntry
{
    // ── Identity ──────────────────────────────────────
    private final String id;
    private final String name;
    private final String category;
    private final String description;

    // ── Maven coordinates ─────────────────────────────
    private final String groupId;
    private final String artifactId;
    private final String version;

    // ── Upstream library ──────────────────────────────
    private final String upstreamName;
    private final String upstreamVersion;
    private final String upstreamUrl;

    // ── JPMS ──────────────────────────────────────────
    private final String jpmsModule;

    // ── README & docs ─────────────────────────────────
    private final String readmePath;
    private final String docsUrl;
    private final String sourceUrl;

    // ── Features ──────────────────────────────────────
    private final List<String> features;

    // ── Tech badges ───────────────────────────────────
    private final List<String> techBadges;

    // ── Prerequisites ─────────────────────────────────
    private final List<String> prerequisites;

    // ── NPM dependencies (name → version) ─────────────
    private final Map<String, String> npmDependencies;

    // ── Quick start snippet ───────────────────────────
    private final String quickStartCode;
    private final String quickStartLanguage;

    // ── Installation snippet ──────────────────────────
    private final String mavenSnippet;
    private final String gradleSnippet;

    // ── License info ──────────────────────────────────
    private final boolean requiresLicense;
    private final String licenseNote;

    // ── SPI extensions provided ───────────────────────
    private final List<String> spiProvides;

    // ── SPI extensions consumed ───────────────────────
    private final List<String> spiUses;

    // ── Components (Java classes exposed by this plugin) ──
    private final List<ComponentInfo> components;

    // ── Code examples ─────────────────────────────────
    private final List<ExampleSnippet> examples;

    // ── SPI detail explanations ───────────────────────
    private final List<SpiDetail> spiDetails;

    // ── Configuration options ─────────────────────────
    private final List<ConfigEntry> configurations;

    // ══════════════════════════════════════════════════
    //  Inner record types
    // ══════════════════════════════════════════════════

    /**
     * A Java component class exposed by this plugin.
     */
    public record ComponentInfo(String className, String description, String packageName) {}

    /**
     * A code example demonstrating usage.
     */
    public record ExampleSnippet(String title, String description, String code, String language) {}

    /**
     * Detailed explanation of an SPI extension point.
     */
    public record SpiDetail(String interfaceName, String direction, String description) {}

    /**
     * A configuration property or option.
     */
    public record ConfigEntry(String name, String type, String defaultValue, String description) {}

    private PluginEntry(Builder builder)
    {
        this.id = builder.id;
        this.name = builder.name;
        this.category = builder.category;
        this.description = builder.description;
        this.groupId = builder.groupId;
        this.artifactId = builder.artifactId;
        this.version = builder.version;
        this.upstreamName = builder.upstreamName;
        this.upstreamVersion = builder.upstreamVersion;
        this.upstreamUrl = builder.upstreamUrl;
        this.jpmsModule = builder.jpmsModule;
        this.readmePath = builder.readmePath;
        this.docsUrl = builder.docsUrl;
        this.sourceUrl = builder.sourceUrl;
        this.features = builder.features == null ? List.of() : Collections.unmodifiableList(builder.features);
        this.techBadges = builder.techBadges == null ? List.of() : Collections.unmodifiableList(builder.techBadges);
        this.prerequisites = builder.prerequisites == null ? List.of() : Collections.unmodifiableList(builder.prerequisites);
        this.npmDependencies = builder.npmDependencies == null ? Map.of() : Collections.unmodifiableMap(builder.npmDependencies);
        this.quickStartCode = builder.quickStartCode;
        this.quickStartLanguage = builder.quickStartLanguage;
        this.mavenSnippet = builder.mavenSnippet;
        this.gradleSnippet = builder.gradleSnippet;
        this.requiresLicense = builder.requiresLicense;
        this.licenseNote = builder.licenseNote;
        this.spiProvides = builder.spiProvides == null ? List.of() : Collections.unmodifiableList(builder.spiProvides);
        this.spiUses = builder.spiUses == null ? List.of() : Collections.unmodifiableList(builder.spiUses);
        this.components = builder.components == null ? List.of() : Collections.unmodifiableList(builder.components);
        this.examples = builder.examples == null ? List.of() : Collections.unmodifiableList(builder.examples);
        this.spiDetails = builder.spiDetails == null ? List.of() : Collections.unmodifiableList(builder.spiDetails);
        this.configurations = builder.configurations == null ? List.of() : Collections.unmodifiableList(builder.configurations);
    }

    public static Builder builder(String id, String name, String category, String groupId, String artifactId)
    {
        return new Builder(id, name, category, groupId, artifactId);
    }

    public static final class Builder
    {
        private final String id;
        private final String name;
        private final String category;
        private final String groupId;
        private final String artifactId;

        private String description;
        private String version = "2.0.0-SNAPSHOT";
        private String upstreamName;
        private String upstreamVersion;
        private String upstreamUrl;
        private String jpmsModule;
        private String readmePath;
        private String docsUrl;
        private String sourceUrl;
        private List<String> features;
        private List<String> techBadges;
        private List<String> prerequisites;
        private Map<String, String> npmDependencies;
        private String quickStartCode;
        private String quickStartLanguage = "java";
        private String mavenSnippet;
        private String gradleSnippet;
        private boolean requiresLicense;
        private String licenseNote;
        private List<String> spiProvides;
        private List<String> spiUses;
        private List<ComponentInfo> components;
        private List<ExampleSnippet> examples;
        private List<SpiDetail> spiDetails;
        private List<ConfigEntry> configurations;

        private Builder(String id, String name, String category, String groupId, String artifactId)
        {
            this.id = id;
            this.name = name;
            this.category = category;
            this.groupId = groupId;
            this.artifactId = artifactId;
        }

        public Builder description(String val) { description = val; return this; }
        public Builder version(String val) { version = val; return this; }
        public Builder upstreamName(String val) { upstreamName = val; return this; }
        public Builder upstreamVersion(String val) { upstreamVersion = val; return this; }
        public Builder upstreamUrl(String val) { upstreamUrl = val; return this; }
        public Builder jpmsModule(String val) { jpmsModule = val; return this; }
        public Builder readmePath(String val) { readmePath = val; return this; }
        public Builder docsUrl(String val) { docsUrl = val; return this; }
        public Builder sourceUrl(String val) { sourceUrl = val; return this; }
        public Builder features(List<String> val) { features = val; return this; }
        public Builder techBadges(List<String> val) { techBadges = val; return this; }
        public Builder prerequisites(List<String> val) { prerequisites = val; return this; }
        public Builder npmDependencies(Map<String, String> val) { npmDependencies = val; return this; }
        public Builder quickStartCode(String val) { quickStartCode = val; return this; }
        public Builder quickStartLanguage(String val) { quickStartLanguage = val; return this; }
        public Builder mavenSnippet(String val) { mavenSnippet = val; return this; }
        public Builder gradleSnippet(String val) { gradleSnippet = val; return this; }
        public Builder requiresLicense(boolean val) { requiresLicense = val; return this; }
        public Builder licenseNote(String val) { licenseNote = val; return this; }
        public Builder spiProvides(List<String> val) { spiProvides = val; return this; }
        public Builder spiUses(List<String> val) { spiUses = val; return this; }
        public Builder components(List<ComponentInfo> val) { components = val; return this; }
        public Builder examples(List<ExampleSnippet> val) { examples = val; return this; }
        public Builder spiDetails(List<SpiDetail> val) { spiDetails = val; return this; }
        public Builder configurations(List<ConfigEntry> val) { configurations = val; return this; }

        public PluginEntry build()
        {
            return new PluginEntry(this);
        }
    }
}

package com.jwebmp.webawesomepro.implementations;

import com.google.common.base.Strings;
import com.jwebmp.core.base.angular.services.interfaces.NpmrcConfigurator;
import com.jwebmp.webawesomepro.WebAwesomeProPageConfigurator;

import java.util.Set;

/**
 * Configures the .npmrc file with the Web Awesome Pro private Cloudsmith registry
 * when {@link WebAwesomeProPageConfigurator#isUseNpm()} is enabled.
 * <p>
 * The generated .npmrc lines will set up:
 * <ul>
 *     <li>The scoped registry for @web.awesome.me packages</li>
 *     <li>The auth token (from explicit value or ${WEBAWESOME_NPM_TOKEN} env variable)</li>
 * </ul>
 */
public class WebAwesomeProNpmrcConfigurator implements NpmrcConfigurator
{
    @Override
    public Set<String> lines()
    {
        if (WebAwesomeProPageConfigurator.isUseNpm())
        {
            String authToken = Strings.isNullOrEmpty(WebAwesomeProPageConfigurator.getNpmToken())
                    ? "${WEBAWESOME_NPM_TOKEN}"
                    : WebAwesomeProPageConfigurator.getNpmToken();

            return Set.of(
                    "@web.awesome.me:registry=https://npm.cloudsmith.io/fortawesome/webawesome-pro/",
                    "//npm.cloudsmith.io/fortawesome/webawesome-pro/:_authToken=" + authToken
            );
        }

        return Set.of();
    }
}

package com.jwebmp.webawesomepro.implementations;

import com.google.common.base.Strings;
import com.jwebmp.core.base.angular.services.interfaces.NpmrcConfigurator;
import com.jwebmp.webawesomepro.WebAwesomeProPageConfigurator;

import java.util.Set;

/**
 * Configures the .npmrc file with the Web Awesome Pro private Cloudsmith registry.
 * <p>
 * The scoped registry line is always emitted since the {@code @web.awesome.me/webawesome-pro}
 * dependency is always present in package.json when this module is on the classpath.
 * Without it, npm would attempt to resolve the package from the public registry and get a 404.
 * <p>
 * The auth token is resolved from either:
 * <ul>
 *     <li>An explicit value set via {@link WebAwesomeProPageConfigurator#setNpmToken(String)}</li>
 *     <li>The {@code ${WEBAWESOME_NPM_TOKEN}} environment variable placeholder (default)</li>
 * </ul>
 */
public class WebAwesomeProNpmrcConfigurator implements NpmrcConfigurator
{
    @Override
    public Set<String> lines()
    {
        String authToken = Strings.isNullOrEmpty(WebAwesomeProPageConfigurator.getNpmToken())
                ? "${WEBAWESOME_NPM_TOKEN}"
                : WebAwesomeProPageConfigurator.getNpmToken();

        return Set.of(
                "@web.awesome.me:registry=https://npm.cloudsmith.io/fortawesome/webawesome-pro/",
                "//npm.cloudsmith.io/fortawesome/webawesome-pro/:_authToken=" + authToken
        );
    }
}

package com.jwebmp.core.base.angular.modules.services.angular;

import com.fasterxml.jackson.core.JsonGenerator;
import com.fasterxml.jackson.core.JsonProcessingException;
import com.fasterxml.jackson.databind.DeserializationFeature;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.SerializationFeature;
import com.google.common.base.Strings;
import com.google.inject.Singleton;
import com.guicedee.client.IGuiceContext;
import com.jwebmp.core.base.angular.client.annotations.angular.NgModule;
import com.jwebmp.core.base.angular.client.annotations.boot.NgBootModuleImport;
import com.jwebmp.core.base.angular.client.annotations.references.NgComponentReference;
import com.jwebmp.core.base.angular.client.annotations.references.NgImportReference;
import com.jwebmp.core.base.angular.client.annotations.routing.NgRoutable;
import com.jwebmp.core.base.angular.client.annotations.typescript.TsDependency;
import com.jwebmp.core.base.angular.client.services.interfaces.*;
import com.jwebmp.core.base.angular.services.DefinedRoute;
import com.jwebmp.core.base.interfaces.IComponentHTMLAttributeBase;
import com.jwebmp.core.base.interfaces.IComponentHierarchyBase;
import io.github.classgraph.ClassInfo;
import io.github.classgraph.ScanResult;
import lombok.extern.log4j.Log4j2;

import java.util.*;
import java.util.function.Predicate;
import java.util.stream.Collectors;

import static com.guicedee.client.implementations.ObjectBinderKeys.DefaultObjectMapper;
import static com.jwebmp.core.base.angular.client.services.interfaces.AnnotationUtils.getNgComponentReference;
import static com.jwebmp.core.base.angular.client.services.interfaces.AnnotationUtils.getTsFilename;


@NgImportReference(value = "RouterModule, ParamMap,Router", reference = "@angular/router")
@NgImportReference(value = "Routes", reference = "@angular/router")

@NgBootModuleImport("RoutingModule")
@TsDependency(value = "@angular/router", version = "^20.3.17")

@NgModule
//So the initial load sets the app
@Singleton
@Log4j2
public class AngularRoutingModule implements INgModule<AngularRoutingModule> {
    private Class<INgApp<?>> app;
    private List<DefinedRoute<?>> definedRoutesList;
    private static final List<DefinedRoute<?>> routes = Collections.synchronizedList(new ArrayList<>());

    private static RoutingModuleOptions options;

    public static RoutingModuleOptions getOptions() {
        if (options == null) {
            options = new RoutingModuleOptions();
        }
        return options;
    }

    public static List<DefinedRoute<?>> getRoutes(Class<INgApp<?>> app) {
        if (routes.isEmpty()) {
            try {
                new AngularRoutingModule().setApp(app)
                        .buildRoutes();
            } catch (Throwable T) {
                log.error("Failed to build Angular routing module routes", T);
            }
        }

        // Return a snapshot to avoid ConcurrentModificationException during iteration
        synchronized (routes) {
            return new ArrayList<>(routes);
        }
    }

    @Override
    public Set<String> moduleImports() {
        if (options == null) {
            return Set.of("RouterModule.forRoot(routes)");
        } else {
            try {
                return Set.of("RouterModule.forRoot(routes," + new ObjectMapper()
                        .disable(JsonGenerator.Feature.QUOTE_FIELD_NAMES)
                        .enable(DeserializationFeature.READ_ENUMS_USING_TO_STRING)
                        .enable(SerializationFeature.WRITE_ENUMS_USING_TO_STRING)
                        .writeValueAsString(options) + ")");
            } catch (JsonProcessingException e) {
                throw new RuntimeException(e);
            }
        }
    }

    @Override
    public AngularRoutingModule setApp(INgApp<?> app) {
        if (app != null) {
            this.app = (Class<INgApp<?>>) app.getClass();
        }
        return this;
    }

    public AngularRoutingModule setApp(Class<INgApp<?>> app) {
        this.app = app;
        return this;
    }

    @Override
    public List<String> exports() {
        return List.of("RouterModule");
    }

    @Override
    public List<NgImportReference> getAllImportAnnotations() {
        List<NgImportReference> out = INgModule.super.getAllImportAnnotations();
        if (definedRoutesList == null) {
            buildRoutes();
        }
        if (definedRoutesList != null) {
            for (DefinedRoute<?> definedRoute : definedRoutesList) {
                NgComponentReference ngComponentReference = getNgComponentReference(definedRoute.getComponent());
                out.addAll(putRelativeLinkInMap(getClass(), ngComponentReference));
                buildImportReferenceNest(out, definedRoute);
            }
        }
        return out;
    }

    private void buildImportReferenceNest(List<NgImportReference> out, DefinedRoute<?> definedRoute) {
        List<DefinedRoute<?>> dChildren = definedRoute.getChildren();
        for (DefinedRoute<?> dChild : dChildren) {
            out.addAll(addImportToMap(dChild));
            buildImportReferenceNest(out, dChild);
        }
    }

    public void buildRoutes() {
        if (this.app == null) {
            throw new UnsupportedOperationException("No app has been set in the AngularRoutingModule");
        }
        ScanResult scan = IGuiceContext.instance()
                .getScanResult();

        Map<Class<? extends IComponent<?>>, String> baseRoutes = new LinkedHashMap<>();
        definedRoutesList = new ArrayList<>();
        scan
                .getClassesWithAnnotation(NgRoutable.class)
                .stream()
                .sorted(Comparator.comparingInt(o -> o.loadClass()
                        .getAnnotation(NgRoutable.class)
                        .sortOrder()))
                .forEach(a -> {
                            Class<? extends INgComponent<?>> aClass = (Class<? extends INgComponent<?>>) a.loadClass();
                            var component = IGuiceContext.get(aClass);
                            var nApp = IGuiceContext.get(this.app);
                            nApp.getRoutes()
                                    .add((IComponentHierarchyBase<?, ?>) component);
                            NgRoutable annotation = aClass.getAnnotation(NgRoutable.class);
                            if (annotation != null) {
                                if (annotation.parent().length == 0) {
                                    baseRoutes.put(aClass, annotation.path());
                                }
                            }
                        }
                );
        baseRoutes.forEach((aClass, aName) -> {
            DefinedRoute<?> dr = getDefinedRoute(aClass);
            buildRoutePathway(dr, aClass, true);
            definedRoutesList.add(dr);
            routes.add(dr);
        });
        // Iterate over a snapshot to avoid ConcurrentModificationException in multi-threaded contexts
        for (DefinedRoute<?> definedRoute : new ArrayList<>(definedRoutesList)) {
            if (definedRoute.getComponent() != null) {
                List<NgImportReference> refs = new ArrayList<>();
                buildRoutePathwayImports(definedRoute, refs);
            }
        }
    }

    private DefinedRoute<?> getDefinedRoute(Class<? extends IComponent<?>> aClass) {
        DefinedRoute<?> dr = new DefinedRoute<>();
        NgRoutable annotation = aClass.getAnnotation(NgRoutable.class);
        dr.setPath(annotation.path());
        dr.setRenderComponent(!annotation.ignoreComponent());
        dr.setComponent(aClass);
        dr.setComponentName(getTsFilename(aClass));

        if (!Strings.isNullOrEmpty(annotation.redirectTo())) {
            dr.setRedirectTo(annotation.redirectTo());
        }
        if (!Strings.isNullOrEmpty(annotation.pathMatch())) {
            dr.setPathMatch(annotation.pathMatch());
        }
        if (!Strings.isNullOrEmpty(annotation.outlet())) {
            dr.setOutlet(annotation.outlet());
        }
        return dr;
    }

    private List<NgImportReference> addImportToMap(DefinedRoute<?> definedRoute) {
        NgComponentReference reference = getNgComponentReference(definedRoute.getComponent());
        if (definedRoute.getComponent() != null) {
            return putRelativeLinkInMap(getClass(), reference);
        }
        return new ArrayList<>();
    }

    private List<NgImportReference> buildRoutePathwayImports(DefinedRoute<?> definedRoute, List<NgImportReference> out) {
        for (DefinedRoute<?> child : definedRoute.getChildren()) {
            if (child.getComponent() != null) {
                out.addAll(addImportToMap(child));
                out.addAll(buildRoutePathwayImports(child, out));
            }
        }

        return out;
    }

    private void buildRoutePathway(DefinedRoute parentRoute,
                                   Class<? extends IComponent<?>> aClass, boolean first) {
        DefinedRoute<?> innerDr = getDefinedRoute(aClass);
        if (!first) {
            parentRoute.addChild(innerDr);
        } else {
            innerDr = parentRoute;
        }

        first = false;
        for (Class<? extends IComponent<?>> componentsWithParentClass : componentsWithParenClassAs(aClass)) {
            buildRoutePathway(innerDr, componentsWithParentClass, first);
        }
    }

    List<Class<? extends IComponent<?>>> componentsWithParenClassAs(Class<? extends IComponent<?>> clazz) {
        List<Class<? extends IComponent<?>>> out = new ArrayList<>();

        for (ClassInfo classInfo : IGuiceContext.instance()
                .getScanResult()
                .getClassesWithAnnotation(NgRoutable.class)) {
            if (classInfo.isAbstract() || classInfo.isInterface()) {
                continue;
            }
            NgRoutable routable = classInfo.loadClass()
                    .getAnnotation(NgRoutable.class);
            for (Class<? extends IComponent<?>> aClass : routable.parent()) {
                if (aClass.equals(clazz)) {
                    out.add((Class<? extends IComponent<?>>) classInfo.loadClass());
                }
            }
        }
        return out;
    }

    static <K, V> Map<K, V> filterByValue(Map<K, V> map, Predicate<V> predicate) {
        return map.entrySet()
                .stream()
                .filter(entry -> predicate.test(entry.getValue()))
                .collect(Collectors.toMap(Map.Entry::getKey, Map.Entry::getValue));
    }


    @Override
    public String renderBeforeClass() {
        //render the const class
        ObjectMapper om = IGuiceContext.get(DefaultObjectMapper);
        try {
            String routesOutput = om.writerWithDefaultPrettyPrinter()
                    .writeValueAsString(definedRoutesList);
            routesOutput = "export const routes: Routes = " + routesOutput + ";\n";
            return routesOutput;
        } catch (JsonProcessingException e) {
            e.printStackTrace();
        }
        return "";
    }

    public static <T extends IComponentHTMLAttributeBase<?, ?>> T applyRoute(T component,
                                                                             String pathRoute,
                                                                             String variablePath) {
        if (pathRoute.startsWith("'")) {
            pathRoute = pathRoute.substring(1);
        }
        if (pathRoute.endsWith("'")) {
            pathRoute = pathRoute.substring(0, pathRoute.length() - 1);
        }


        component.addAttribute("[routerLink]", "['" + pathRoute + "'" + (Strings.isNullOrEmpty(variablePath) ? "" : "," +
                variablePath) + "]");

        component.asHierarchyBase()
                .addConfiguration(AnnotationUtils.getNgImportReference("RouterModule", "@angular/router"));
        component.asHierarchyBase()
                .addConfiguration(AnnotationUtils.getNgImportModule("RouterModule"));
        return component;
    }

    public static void applyRequired(IComponentHierarchyBase<?, ?> component) {

        component.asHierarchyBase()
                .addConfiguration(AnnotationUtils.getNgImportReference("RouterModule", "@angular/router"));
        component.asHierarchyBase()
                .addConfiguration(AnnotationUtils.getNgImportModule("RouterModule"));
    }

    public static <T extends IComponentHTMLAttributeBase<?, ?>> T applyRoute(T component,
                                                                             Class<? extends INgComponent<?>> pathRoute) {
        applyRoute(component, pathRoute, "");

        component.asHierarchyBase()
                .addConfiguration(AnnotationUtils.getNgImportReference("RouterModule", "@angular/router"));
        component.asHierarchyBase()
                .addConfiguration(AnnotationUtils.getNgImportModule("RouterModule"));
        return component;
    }

